    try:
        decompressed = zlib.decompress(match.group(1))
        # Look for text in parentheses
        texts = re.findall(rb'\((.*?)\)', decompressed)
        for t in texts:
            try:
                decoded = t.decode('utf-8', errors='ignore')
                if len(decoded) > 2:
                    text_parts.append(decoded)
            except:
                pass
    except:
        pass

print('\\n'.join(text_parts[:200]))
