import zlib, re

with open('/workspaces/keep-base-models-claude/papers/kirk2023_rlhf_diversity.pdf', 'rb') as f:
    data = f.read()

all_text = []
for i, match in enumerate(re.finditer(rb'stream\r?\n(.*?)\r?\nendstream', data, re.DOTALL)):
    raw = match.group(1)
    try:
        decompressed = zlib.decompress(raw)
    except:
        decompressed = raw

    if b'BT' in decompressed:
        # TJ arrays
        for tj in re.finditer(rb'\[(.*?)\]\s*TJ', decompressed, re.DOTALL):
            strings = re.findall(rb'\((.*?)\)', tj.group(1))
            joined = b''.join(strings)
            try:
                all_text.append(joined.decode('latin-1'))
            except:
                pass
        # Tj strings
        for tj in re.finditer(rb'\((.*?)\)\s*Tj', decompressed):
            try:
                all_text.append(tj.group(1).decode('latin-1'))
            except:
                pass

full = ' '.join(all_text)
print(full[:5000])
print('---')
print(f'Total text length: {len(full)}')
" 2>&1

